INSERT OR REPLACE INTO categories (slug, name, short_name, blurb, palette_from, palette_to, sort_order) VALUES ('sacred-painting', 'Sacred Painting', 'Painting', 'Oil, tempera, and fresco — the slow craft of pigment laid over time, in service of the sacred image.', '#7a1f2c', '#42101a', 0);
INSERT OR REPLACE INTO categories (slug, name, short_name, blurb, palette_from, palette_to, sort_order) VALUES ('iconography', 'Iconography', 'Icons', 'Egg tempera and gold leaf in the Byzantine canon. Written, not merely painted — windows into heaven.', '#a8893f', '#5e1623', 1);
INSERT OR REPLACE INTO categories (slug, name, short_name, blurb, palette_from, palette_to, sort_order) VALUES ('sculpture', 'Sculpture', 'Sculpture', 'Stone, bronze, and wood. Bodies, beasts, and saints rendered in three dimensions for chapel and home.', '#6b5e48', '#1c160e', 2);
INSERT OR REPLACE INTO categories (slug, name, short_name, blurb, palette_from, palette_to, sort_order) VALUES ('stained-glass-mosaic', 'Stained Glass & Mosaic', 'Glass & Mosaic', 'Light passing through coloured glass; tesserae set into mortar. The architecture of the luminous.', '#1d3a6b', '#142a51', 3);
INSERT OR REPLACE INTO categories (slug, name, short_name, blurb, palette_from, palette_to, sort_order) VALUES ('sacred-music', 'Sacred Music', 'Music', 'Mass settings, motets, hymns, and chant. Composed for the liturgy, for the choir, for the household.', '#535835', '#1c160e', 4);
INSERT OR REPLACE INTO categories (slug, name, short_name, blurb, palette_from, palette_to, sort_order) VALUES ('sacred-poetry', 'Sacred Poetry', 'Poetry', 'Sonnets, litanies, occasional verse. Words chosen with care for births, weddings, funerals, feast days.', '#7a1f2c', '#a8893f', 5);
INSERT OR REPLACE INTO categories (slug, name, short_name, blurb, palette_from, palette_to, sort_order) VALUES ('liturgical-drama', 'Liturgical Drama', 'Drama', 'Mystery plays, miracle plays, scripted devotions for parish, school, and stage.', '#5e1623', '#3a3024', 6);
INSERT OR REPLACE INTO categories (slug, name, short_name, blurb, palette_from, palette_to, sort_order) VALUES ('image-making', 'Photography & Image-Making', 'Photography', 'Portrait, pilgrimage, liturgy. The patient art of seeing, framed for the wall and the page.', '#1d3a6b', '#3a3024', 7);

INSERT OR REPLACE INTO saints (slug, name, also, feast_month, feast_day, patron_of, blurb, palette_from, palette_to) VALUES ('mary', 'Blessed Virgin Mary', '["Mary","Theotokos","Our Lady","Madonna"]', 1, 1, '["motherhood","the Church","the Americas"]', 'Mother of God under many titles. Most-depicted of all sacred subjects.', '#3a4d8f', '#15214c');
