INSERT OR REPLACE INTO saints (slug, name, also, feast_month, feast_day, patron_of, blurb, palette_from, palette_to) VALUES ('michael', 'St. Michael the Archangel', '["Michael","Archangel"]', 9, 29, '["soldiers","police","those in spiritual combat"]', 'The captain of the heavenly host. Defender against the powers of darkness.', '#7e1414', '#2c0606');
INSERT OR REPLACE INTO saints (slug, name, also, feast_month, feast_day, patron_of, blurb, palette_from, palette_to) VALUES ('patrick', 'St. Patrick of Ireland', '["Patrick"]', 3, 17, '["Ireland","engineers","exiles"]', 'Bishop, missionary, slave-turned-evangelist who brought the Gospel to Ireland.', '#3f6c44', '#1a2e1d');
INSERT OR REPLACE INTO saints (slug, name, also, feast_month, feast_day, patron_of, blurb, palette_from, palette_to) VALUES ('francis', 'St. Francis of Assisi', '["Francis"]', 10, 4, '["the poor","ecology","Italy","animals"]', 'Stigmatic, founder of the Friars Minor. Preached to the birds; rebuilt the Church.', '#a07943', '#4a3517');
INSERT OR REPLACE INTO saints (slug, name, also, feast_month, feast_day, patron_of, blurb, palette_from, palette_to) VALUES ('therese', 'St. Thérèse of Lisieux', '["Thérèse","Therese","Little Flower"]', 10, 1, '["missions","the sick","the small"]', 'Doctor of the Church. The Little Way: ordinary love as the path to holiness.', '#c87f8c', '#5a2f3a');
