INSERT OR REPLACE INTO saints (slug, name, also, feast_month, feast_day, patron_of, blurb, palette_from, palette_to) VALUES ('thomas-aquinas', 'St. Thomas Aquinas', '["Aquinas","the Angelic Doctor"]', 1, 28, '["students","universities","philosophers"]', 'Dominican friar and Doctor of the Church. Wedded reason to revelation.', '#3a3f6e', '#13162e');
