INSERT OR REPLACE INTO saints (slug, name, also, feast_month, feast_day, patron_of, blurb, palette_from, palette_to) VALUES ('padre-pio', 'St. Padre Pio', '["Padre Pio","Pio of Pietrelcina"]', 9, 23, '["civil defense","stress relief","adolescents"]', 'Capuchin friar, stigmatic, confessor of nations.', '#5a4636', '#231914');
