INSERT OR REPLACE INTO saints (slug, name, also, feast_month, feast_day, patron_of, blurb, palette_from, palette_to) VALUES ('bernadette', 'St. Bernadette of Lourdes', '["Bernadette","Lourdes"]', 4, 16, '["the sick","the poor","those mocked for piety"]', 'Visionary of Lourdes. "I am the Immaculate Conception."', '#9aaad3', '#39456b');
